//! Executable proof for `star-toml-pack`'s generated config-admission module
//! (`src/star_toml_config.rs`).
//!
//! GENERATED by `star-toml-pack` -- but unlike `star_toml_config.rs.tmpl` /
//! `star_toml_section_doc.md.tmpl`, this file carries NO `sparql:` frontmatter
//! and loops over NO ontology query. Every expected literal below was
//! hand-transcribed directly from `packs/star-toml-pack/ontology.ttl`'s two
//! `stp:ConfigSection` and four `stp:ConfigField` individuals, independently
//! of the `a_sections`/`fields` SPARQL queries that produced the struct
//! shape under test. Looping that same query into this test's "expected"
//! values too would let a wrong `fieldName`/`rustType` literal, or a broken
//! `pascal_case`/`snake_case` filter, corrupt the generated code and this
//! test's expectations identically -- the test could never catch it.
//! Hardcoding breaks that coupling.
//!
//! Exercises the real `star_toml::load_file` parse+deserialize path against
//! real `TempDir`-backed TOML files -- no mocks, no stubs.
//!
//! `retry_count` (the ontology's one `stp:required=false` field) is
//! deliberately omitted from every fixture below except
//! `optional_field_omitted_deserializes_as_none` -- proving `stp:required`
//! actually reshapes the generated struct (`Option<u32>` + `#[serde(default)]`)
//! rather than merely documenting an assumption already baked into the
//! template.

#[path = "../src/star_toml_config.rs"]
mod star_toml_config;

use star_toml_config::{AdmissionConfig, StarTomlConfig, TelemetryConfig};
use tempfile::TempDir;

/// Structural proof: this literal construction only compiles if
/// `StarTomlConfig` has exactly the two `stp:ConfigSection` fields
/// (`admission`, `telemetry`) and each leaf struct has exactly the
/// `stp:ConfigField` name/type pairs from `ontology.ttl`
/// (`witness_dir: PathBuf`, `fail_closed: bool`, `exporter_endpoint: String`,
/// `sample_rate: f64`) -- proving section/field count and shape by
/// construction, not by re-querying the ontology.
#[test]
fn structural_shape_matches_ontology() {
    let cfg = StarTomlConfig {
        admission: AdmissionConfig {
            witness_dir: std::path::PathBuf::from(".witness"),
            fail_closed: true,
        },
        telemetry: TelemetryConfig {
            exporter_endpoint: "http://otel-collector:4318".to_string(),
            sample_rate: 0.25,
            retry_count: Some(3),
        },
    };

    assert_eq!(
        cfg.admission.witness_dir,
        std::path::PathBuf::from(".witness")
    );
    assert!(cfg.admission.fail_closed);
    assert_eq!(cfg.telemetry.exporter_endpoint, "http://otel-collector:4318");
    assert_eq!(cfg.telemetry.sample_rate, 0.25);
    assert_eq!(cfg.telemetry.retry_count, Some(3));
}

/// Write `contents` to `name` inside `dir` and return the real path -- a
/// real filesystem write, not an in-memory fake.
fn write_toml(dir: &TempDir, name: &str, contents: &str) -> std::path::PathBuf {
    let path = dir.path().join(name);
    std::fs::write(&path, contents).expect("write real temp toml file");
    path
}

/// Behavioral round-trip: hand-written TOML literals (not derived from any
/// query) written to a real file, loaded through the real
/// `StarTomlConfig::load` -> `star_toml::load_file` path, and compared field
/// by field against the exact literals just written -- proving the real
/// `star_toml` crate's parse+deserialize path works end to end.
#[test]
fn load_round_trip_matches_written_literals() {
    let dir = TempDir::new().expect("real tempdir");
    let path = write_toml(
        &dir,
        "star_toml_proof.toml",
        r#"
[admission]
witness_dir = ".witness"
fail_closed = true

[telemetry]
exporter_endpoint = "http://otel-collector:4318"
sample_rate = 0.25
"#,
    );

    let cfg = StarTomlConfig::load(&path).expect("real admitted config must load");

    assert_eq!(
        cfg.admission.witness_dir,
        std::path::PathBuf::from(".witness")
    );
    assert!(cfg.admission.fail_closed);
    assert_eq!(cfg.telemetry.exporter_endpoint, "http://otel-collector:4318");
    assert_eq!(cfg.telemetry.sample_rate, 0.25);
}

/// Fail-closed: an unknown key inside `[admission]` must be rejected --
/// proves `#[serde(deny_unknown_fields)]` on `AdmissionConfig` is
/// load-bearing, not decorative.
#[test]
fn unknown_key_in_admission_is_rejected() {
    let dir = TempDir::new().expect("real tempdir");
    let path = write_toml(
        &dir,
        "star_toml_unknown_key.toml",
        r#"
[admission]
witness_dir = ".witness"
fail_closed = true
unexpected_extra_key = "not part of the ontology-derived schema"

[telemetry]
exporter_endpoint = "http://otel-collector:4318"
sample_rate = 0.25
"#,
    );

    let result = StarTomlConfig::load(&path);
    assert!(
        result.is_err(),
        "unknown key `unexpected_extra_key` in [admission] must be rejected, not silently accepted"
    );
}

/// Fail-closed: a missing required field (`fail_closed` omitted from
/// `[admission]`) must be rejected, not silently defaulted.
#[test]
fn missing_required_field_is_rejected() {
    let dir = TempDir::new().expect("real tempdir");
    let path = write_toml(
        &dir,
        "star_toml_missing_field.toml",
        r#"
[admission]
witness_dir = ".witness"

[telemetry]
exporter_endpoint = "http://otel-collector:4318"
sample_rate = 0.25
"#,
    );

    let result = StarTomlConfig::load(&path);
    assert!(
        result.is_err(),
        "missing required field `fail_closed` must be rejected, not defaulted"
    );
}

/// `stp:required=false` proof: `retry_count` omitted from `[telemetry]`
/// must deserialize as `None`, not be rejected and not silently default to
/// a hardcoded numeric value -- proving `#[serde(default)]` on an
/// `Option<u32>` field, not `deny_unknown_fields` swallowing it.
#[test]
fn optional_field_omitted_deserializes_as_none() {
    let dir = TempDir::new().expect("real tempdir");
    let path = write_toml(
        &dir,
        "star_toml_optional_omitted.toml",
        r#"
[admission]
witness_dir = ".witness"
fail_closed = true

[telemetry]
exporter_endpoint = "http://otel-collector:4318"
sample_rate = 0.25
"#,
    );

    let cfg = StarTomlConfig::load(&path).expect("omitting an optional field must still admit");
    assert_eq!(
        cfg.telemetry.retry_count, None,
        "omitted stp:required=false field must deserialize as None, not panic or default to a number"
    );
}

/// Fail-closed: a missing file must return `Err`, never panic --
/// `star_toml::load_file` returns `Error::FileNotFound`, not an unwrap panic.
#[test]
fn missing_file_is_rejected_not_panicked() {
    let dir = TempDir::new().expect("real tempdir");
    let path = dir.path().join("does_not_exist.toml");

    let result = StarTomlConfig::load(&path);
    assert!(
        result.is_err(),
        "missing config file must return Err, not panic"
    );
}

/// Behavior-contract proof (round 3): `sample_rate` carries `stp:minValue
/// 0.0` / `stp:maxValue 1.0` in `ontology.ttl`. `serde::Deserialize` alone
/// cannot and does not check this -- a syntactically valid TOML file with
/// `sample_rate = 1.5` parses successfully via `StarTomlConfig::load`.
/// `validate()` is the ontology-projected pre-condition check that catches
/// it; this test proves `load()` succeeding is NOT the same as the value
/// being admissible.
#[test]
fn out_of_range_sample_rate_parses_but_fails_validate() {
    let dir = TempDir::new().expect("real tempdir");
    let path = write_toml(
        &dir,
        "star_toml_out_of_range.toml",
        r#"
[admission]
witness_dir = ".witness"
fail_closed = true

[telemetry]
exporter_endpoint = "http://otel-collector:4318"
sample_rate = 1.5
"#,
    );

    let cfg = StarTomlConfig::load(&path)
        .expect("out-of-range sample_rate is still syntactically valid TOML/type-correct");
    assert_eq!(cfg.telemetry.sample_rate, 1.5, "load() does not clamp or reject the value");

    let result = cfg.validate();
    assert!(
        result.is_err(),
        "validate() must reject sample_rate=1.5 against stp:minValue=0.0/stp:maxValue=1.0"
    );
    assert!(
        result.unwrap_err().contains("sample_rate"),
        "error must name the violated field"
    );
}

/// Behavior-contract proof: an in-range `sample_rate` must pass `validate()`
/// on both the leaf section and the aggregate `StarTomlConfig::validate()`.
#[test]
fn in_range_sample_rate_passes_validate() {
    let dir = TempDir::new().expect("real tempdir");
    let path = write_toml(
        &dir,
        "star_toml_in_range.toml",
        r#"
[admission]
witness_dir = ".witness"
fail_closed = true

[telemetry]
exporter_endpoint = "http://otel-collector:4318"
sample_rate = 0.5
"#,
    );

    let cfg = StarTomlConfig::load(&path).expect("real admitted config must load");
    assert!(
        cfg.telemetry.validate().is_ok(),
        "sample_rate=0.5 is within [0.0, 1.0] and must pass section-level validate()"
    );
    assert!(
        cfg.validate().is_ok(),
        "aggregate StarTomlConfig::validate() must also pass when every section passes"
    );
}
